25	const PROCESSING_FEE = 5;
26	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
27	const BUILDING_BLOCK_PREMIUM = 60;
28	const BUILDING_BLOCK_SIZE = 3;
29	const CURSED_SURCHARGE_RATE = 0.5;
30	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
31	const HIGH_ENCHANTMENT_THRESHOLD = 5;
32	const LOYALTY_DISCOUNT_RATE = 0.2;
33	const LOYALTY_YEARS_THRESHOLD = 2;
34	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
35	
36	const BASE_PREMIUMS: Record<string, number> = {
37	  sword: 100,
38	  amulet: 60,
39	  staff: 80,
40	  potion: 40,
41	  rune: 25,
42	};
43	
44	const groupItemsByType = (items: Item[]): Record<string, Item[]> => {
45	  const groups: Record<string, Item[]> = {};
46	  for (const item of items) {
47	    if (!groups[item.type]) {
48	      groups[item.type] = [];
49	    }
50	    groups[item.type].push(item);
51	  }
52	  return groups;
53	};
54	
55	const calculateSingleItemPremium = (item: Item): number => {
56	  const basePremium = BASE_PREMIUMS[item.type];
57	  const cursedSurcharge = item.cursed ? basePremium * CURSED_SURCHARGE_RATE : 0;
58	  const enchantmentSurcharge =
59	    item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
60	      ? basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE
61	      : 0;
62	  return basePremium + cursedSurcharge + enchantmentSurcharge;
63	};
64	
65	const calculateGroupPremium = (typeItems: Item[]): { total: number; base: number } => {
66	  if (typeItems.length === BUILDING_BLOCK_SIZE) {
67	    return { total: BUILDING_BLOCK_PREMIUM, base: BUILDING_BLOCK_PREMIUM };
68	  }
69	  return typeItems.reduce(
70	    (acc, item) => ({
71	      total: acc.total + calculateSingleItemPremium(item),
72	      base: acc.base + BASE_PREMIUMS[item.type],
73	    }),
74	    { total: 0, base: 0 },
75	  );
76	};
77	
78	const calculateItemsPremium = (items: Item[]): { total: number; base: number } => {
79	  const groups = Object.values(groupItemsByType(items));
80	  return groups.reduce(
81	    (acc, group) => {
82	      const groupResult = calculateGroupPremium(group);
83	      return { total: acc.total + groupResult.total, base: acc.base + groupResult.base };
84	    },
85	    { total: 0, base: 0 },
86	  );
87	};
88	
89	const calculateStepPremium = (
90	  step: Step,
91	  customerYears: number,
92	  isFollowUp: boolean,
93	): number => {
94	  const { total: itemsPremium, base: policyBasePremium } = calculateItemsPremium(step.items);
95	  const surcharge = policyBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
96	  const loyaltyDiscount =
97	    customerYears >= LOYALTY_YEARS_THRESHOLD
98	      ? policyBasePremium * LOYALTY_DISCOUNT_RATE
99	      : 0;
100	  const followUpDiscount = isFollowUp ? policyBasePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
101	  return Math.ceil(itemsPremium + surcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
102	};
