104	export function processScenario(scenario: Scenario): ScenarioOutput {
105	  const results = scenario.steps.map((step, index) => {
106	    const premium = calculateStepPremium(step, scenario.customer.years, index > 0);
107	    return { premium };
108	  });
109	  return { results };
110	}
